import{c as t,Q as o,j as d,m as r}from"./chunks/framework.D9IbVcwA.js";const f=JSON.parse('{"title":"014-driver-keyboard-2 · 键盘驱动","description":"","frontmatter":{"title":"014-driver-keyboard-2 · 键盘驱动"},"headers":[],"relativePath":"hands-on/014-driver-keyboard-2.md","filePath":"hands-on/014-driver-keyboard-2.md","lastUpdated":1779686691000}'),a={name:"hands-on/014-driver-keyboard-2.md"};function i(c,e,s,n,h,l){return o(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="_014-2-扫描码解码-查找表与修饰键跟踪" tabindex="-1">014-2 扫描码解码：查找表与修饰键跟踪 <a class="header-anchor" href="#_014-2-扫描码解码-查找表与修饰键跟踪" aria-label="Permalink to &quot;014-2 扫描码解码：查找表与修饰键跟踪&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们跟 8042 PS/2 控制器完成了握手——初始化序列跑通了，自检过了，IRQ1 也 unmask 了。但到头来按键还是没反应，因为我们的 IRQ1 handler 还是个空壳。这一章开始，我们要构建完整的扫描码解码管线。</p><p>具体来说，这一章我们聚焦两件事：第一，建立从扫描码到 ASCII 字符的翻译机制——两张 128 项的查找表（小写和大写），按 US QWERTY 布局填写；第二，实现 Shift/Ctrl/Alt 三个 modifier 键的状态跟踪，让按键的翻译结果随 modifier 变化。IRQ1 handler 的完整实现和环形缓冲区是下一章的事，但这一章要把 handler 需要的所有数据结构和解码逻辑准备好。</p><p>知识前置：上一章的 PS/2 控制器初始化必须已经完成，你需要理解 scan code set 1 的基本格式（make code 是单字节，break code 是 make code | 0x80）。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="扫描码集-1-的-make-break-规则" tabindex="-1">扫描码集 1 的 Make/Break 规则 <a class="header-anchor" href="#扫描码集-1-的-make-break-规则" aria-label="Permalink to &quot;扫描码集 1 的 Make/Break 规则&quot;">​</a></h3><p>在上一章中我们开启了 8042 控制器的翻译模式，所以软件层面看到的始终是扫描码集 1。集 1 的规则极其简单，可以用两句话概括：按键按下（Make）时，控制器发送一个字节，bit 7 为 0；按键松开（Break）时，控制器发送同一个字节但 bit 7 置 1。举个例子，字母 A 的 make code 是 0x1E，那么 break code 就是 0x1E | 0x80 = 0x9E。左 Shift 的 make code 是 0x2A，break code 是 0xAA。</p><p>这个规则的推论也很直观：判断一个字节是按下还是松开，只需要检查 bit 7——为 0 就是按下，为 1 就是松开。提取 make code（键位标识），只需要和 0x7F 做 AND 运算把 bit 7 清掉。整个解码逻辑完全不需要状态机，一个 if-else 就搞定了。</p><p>不过有两类特殊情况我们需要知道但暂时不处理。第一类是扩展前缀 0xE0——方向键、右 Ctrl、右 Alt 等键会在真正的扫描码之前多发送一个 0xE0 字节。0xE0 本身也会触发一次 IRQ1。我们的策略是：如果读到的扫描码是 0xE0，直接发 EOI 然后返回，忽略这次中断。第二类是 Pause/Break 键，它会发送一个 6 字节的序列（0xE1, 0x1D, 0x45, 0xE1, 0x9D, 0xC5），而且没有 break code——这个更罕见，我们也不处理。</p><h3 id="查找表驱动的设计" tabindex="-1">查找表驱动的设计 <a class="header-anchor" href="#查找表驱动的设计" aria-label="Permalink to &quot;查找表驱动的设计&quot;">​</a></h3><p>把扫描码翻译成 ASCII 字符，最直观的方式是一个 128 项的查找表——索引是 make code，值是对应的 ASCII 字符。我们准备两张表：一张是 <code>kScToLower</code>（无 Shift 时的映射，字母映射为小写，数字键映射为数字本身），另一张是 <code>kScToUpper</code>（有 Shift 时的映射，字母映射为大写，数字键映射为符号——比如 &#39;1&#39; 变成 &#39;!&#39;、&#39;2&#39; 变成 &#39;@&#39;）。</p><p>索引 0 表示&quot;无映射&quot;——功能键（F1-F10，扫描码 0x3B-0x44）、modifier 键（Shift、Ctrl、Alt）和其它非打印键在表中的值都是 0。这样解码的时候只需要检查表的返回值是否非零就能判断是不是可打印字符。两张表各 128 个字节，总共 256 字节，用 <code>static constexpr char</code> 数组定义，编译期完全确定，放到 <code>.rodata</code> 段里。</p><p>这种数据驱动的设计比 if-else 链或者 switch-case 好得多：表格是声明式的、可审计的（一眼就能看出映射是否正确），而且添加新的映射只需要改表不需要改逻辑。</p><h3 id="modifier-跟踪机制" tabindex="-1">Modifier 跟踪机制 <a class="header-anchor" href="#modifier-跟踪机制" aria-label="Permalink to &quot;Modifier 跟踪机制&quot;">​</a></h3><p>Shift、Ctrl、Alt 这三个 modifier 键比较特殊——它们自己不产生可打印字符，但会影响其他键的翻译结果。我们需要在每次按键事件到来时更新 modifier 状态，然后在翻译 ASCII 时根据当前状态查不同的表。</p><p>具体做法是维护三个布尔变量：<code>shift_held_</code>、<code>ctrl_held_</code>、<code>alt_held_</code>。每当收到一个 modifier 键的 make code（比如左 Shift 0x2A），把对应的标志设为 true；收到 break code（比如 0xAA），设为 false。注意左 Shift（0x2A）和右 Shift（0x36）都影响同一个 <code>shift_held_</code> 标志——这是因为对于字符大小写来说，左右 Shift 的效果是等价的。Ctrl 和 Alt 暂时只跟踪左键（0x1D 和 0x38），因为右 Ctrl/右 Alt 的扫描码带 0xE0 前缀，我们目前不处理扩展键。</p><p>每个 KeyEvent 结构体在被创建时，都会把当前的 modifier 状态快照进去。这意味着消费者（kernel_main 的轮询循环）拿到的每个事件都是自包含的——不需要自己去查&quot;此刻 Shift 到底有没有被按下&quot;。</p><h3 id="keyevent-结构体" tabindex="-1">KeyEvent 结构体 <a class="header-anchor" href="#keyevent-结构体" aria-label="Permalink to &quot;KeyEvent 结构体&quot;">​</a></h3><p>每个按键事件被封装为一个 KeyEvent 结构体，包含六个字段：<code>ascii</code>（ASCII 字符，如果是非打印键或者松开事件则为 0）、<code>scancode</code>（原始扫描码字节，包含 bit 7 的 press/release 信息）、<code>pressed</code>（true=按下，false=松开）、<code>shift</code>、<code>ctrl</code>、<code>alt</code>（事件发生时的 modifier 快照）。这个结构体的设计让消费者拥有完整的信息——你可以只看 <code>ascii</code> 来处理字符输入，也可以看 <code>scancode</code> 来处理功能键，还可以看 modifier 组合来实现快捷键。</p><blockquote><p>参考：<a href="https://wiki.osdev.org/PS/2_Keyboard" target="_blank" rel="noreferrer">OSDev Wiki - PS/2 Keyboard</a></p></blockquote><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-设计-keyevent-结构体和-keyboard-类骨架" tabindex="-1">Step 1: 设计 KeyEvent 结构体和 Keyboard 类骨架 <a class="header-anchor" href="#step-1-设计-keyevent-结构体和-keyboard-类骨架" aria-label="Permalink to &quot;Step 1: 设计 KeyEvent 结构体和 Keyboard 类骨架&quot;">​</a></h3><p><strong>目标</strong>: 定义按键事件的数据结构和键盘驱动的类接口。</p><p><strong>设计思路</strong>: KeyEvent 是一个纯数据结构（POD 类型），包含上面提到的六个字段。Keyboard 类的所有成员都是 static 的——因为整个系统只有一个 PS/2 键盘控制器，没有理由支持多实例。类的公开接口只有三个方法：<code>init()</code>（上一章已经实现）、<code>irq1_handler()</code>（IRQ1 中断处理，下一章实现）、<code>poll()</code>（从环形缓冲区取出一个事件，返回 bool 表示是否成功取到）。私有成员包括：64 个 KeyEvent 的数组（环形缓冲区）、head 和 tail 指针（uint32_t）、三个 modifier 布尔标志、以及一个 <code>enqueue()</code> 方法。</p><p><strong>实现约束</strong>: 头文件 <code>kernel/drivers/keyboard/keyboard.hpp</code> 中，KeyEvent 放在 <code>cinux::drivers</code> 命名空间中。Keyboard 类也在同一命名空间。前向声明 <code>cinux::arch::InterruptFrame</code>（避免在头文件中 include idt.hpp）。所有 static 成员变量需要在 <code>.cpp</code> 文件中定义（不仅是声明），否则链接时找不到符号。这是 C++ static 成员变量的经典规则——头文件里只是声明，.cpp 里要写 <code>KeyEvent Keyboard::queue_[64] = {};</code> 这样的定义行。</p><p><strong>踩坑预警</strong>: 如果你只在头文件里声明了 static 成员变量但没有在 .cpp 中定义，链接阶段会报 &quot;undefined reference&quot; 错误，而且错误信息指向的是你访问这些变量的每一行代码，非常烦人。另外，KeyEvent 结构体的字段顺序建议是：ascii 在前，然后是 scancode、pressed、三个 modifier——保持和声明顺序一致，避免结构体对齐填充导致不必要的内存浪费。</p><p><strong>验证</strong>: 这一步只涉及类型定义，不需要独立验证。构建成功就说明结构体和类定义没有语法错误。</p><h3 id="step-2-实现扫描码查找表" tabindex="-1">Step 2: 实现扫描码查找表 <a class="header-anchor" href="#step-2-实现扫描码查找表" aria-label="Permalink to &quot;Step 2: 实现扫描码查找表&quot;">​</a></h3><p><strong>目标</strong>: 创建两张 128 项的查找表，实现扫描码集 1 到 ASCII 的翻译。</p><p><strong>设计思路</strong>: <code>kScToLower</code> 表按照 US QWERTY 布局填写。扫描码 0x02-0x0B 对应数字行的 1-9 和 0（注意不是 0-9，&#39;1&#39; 在 0x02，&#39;0&#39; 在 0x0B），0x10-0x1B 对应 QWERTYUIOP 这一行，0x1E-0x28 对应 ASDFGHJKL 这一行，0x2C-0x35 对应 ZXCVBNM 这一行。特殊键：0x01 是 Esc（映射为 ASCII 27），0x0E 是退格（映射为 &#39;\\b&#39;），0x1C 是回车（映射为 &#39;\\n&#39;），0x39 是空格。<code>kScToUpper</code> 表在字母位置映射大写字母，在数字行映射 shift 符号（&#39;1&#39;-&gt;&#39;!&#39;、&#39;2&#39;-&gt;&#39;@&#39;、&#39;3&#39;-&gt;&#39;#&#39;、&#39;4&#39;-&gt;&#39;$&#39;、&#39;5&#39;-&gt;&#39;%&#39;、&#39;6&#39;-&gt;&#39;^&#39;、&#39;7&#39;-&gt;&#39;&amp;&#39;、&#39;8&#39;-&gt;&#39;*&#39;、&#39;9&#39;-&gt;&#39;(&#39;、&#39;0&#39;-&gt;&#39;)&#39;），在标点符号位置也是对应的 shift 版本（&#39;-&#39;-&gt;&#39;_&#39;、&#39;=&#39;-&gt;&#39;+&#39;、&#39;[&#39;-&gt;&#39;{&#39;，等等）。</p><p><strong>实现约束</strong>: 两张表都是 <code>static constexpr char</code> 数组，128 个元素，定义在 <code>keyboard.cpp</code> 中。不可打印的键（功能键、modifier 键、0x00）全部填 0。表的排列建议每行 8 个元素，用注释标注扫描码范围，这样容易对照键盘布局检查。</p><p><strong>踩坑预警</strong>: 填表的时候最容易出错的是数字行——扫描码 0x0A 是 &#39;9&#39;，0x0B 是 &#39;0&#39;，不是 0x09=&#39;9&#39;/0x0A=&#39;0&#39;。如果你把 9 和 0 的位置搞反了，按下 &#39;9&#39; 会输出 &#39;0&#39;，按下 &#39;0&#39; 什么都不输出（因为越界到了下一个条目）。另外，退格键（0x0E）映射为 &#39;\\b&#39; 而不是 0x7F（DEL），这是 PS/2 键盘的标准行为。回车键（0x1C）映射为 &#39;\\n&#39; 而不是 &#39;\\r&#39;，这是我们自己的设计选择——Unix 传统。</p><p><strong>验证</strong>: 构建后运行 host 端测试 <code>ctest --test-dir build -L keyboard</code>，扫描码翻译相关的测试用例应该全部通过。如果你想手动验证，可以检查 <code>kScToLower[0x1E]</code> 是否等于 &#39;a&#39;，<code>kScToUpper[0x1E]</code> 是否等于 &#39;A&#39;，<code>kScToLower[0x02]</code> 是否等于 &#39;1&#39;，<code>kScToUpper[0x02]</code> 是否等于 &#39;!&#39;。</p><h3 id="step-3-实现-modifier-跟踪逻辑" tabindex="-1">Step 3: 实现 modifier 跟踪逻辑 <a class="header-anchor" href="#step-3-实现-modifier-跟踪逻辑" aria-label="Permalink to &quot;Step 3: 实现 modifier 跟踪逻辑&quot;">​</a></h3><p><strong>目标</strong>: 编写 modifier 键的状态更新代码，确保 Shift/Ctrl/Alt 的按下和释放都能正确反映到内部状态中。</p><p><strong>设计思路</strong>: modifier 跟踪的核心逻辑非常简洁：收到一个扫描码后，先提取 make code（<code>sc &amp; 0x7F</code>），然后检查这个 make code 是否属于 modifier 键。如果是左 Shift（0x2A）或右 Shift（0x36），就把 <code>shift_held_</code> 设为 <code>pressed</code> 的值（按下=true，释放=false）。如果是左 Ctrl（0x1D），更新 <code>ctrl_held_</code>。如果是左 Alt（0x38），更新 <code>alt_held_</code>。</p><p>注意这里用的是 <code>pressed</code> 而不是硬编码的 <code>true</code>——这意味着 break code 自然会把标志清零。如果只写 <code>shift_held_ = true</code>，那么 Shift 按下后永远不会&quot;松手&quot;，后续所有按键都会被当成大写来翻译。另外，modifier 跟踪必须在构建 KeyEvent 之前完成——因为 KeyEvent 中的 shift/ctrl/alt 字段是从当前 modifier 状态快照而来的。</p><p><strong>实现约束</strong>: 这段逻辑将作为 <code>irq1_handler()</code> 的一部分实现，放在 <code>keyboard.cpp</code> 中。但你可以先写一个独立函数来验证：接收扫描码和三个 bool 引用参数，执行 modifier 更新。等下一章集成到 irq1_handler 时再内联进去。</p><p><strong>踩坑预警</strong>: 如果 modifier 跟踪只检查 make code 但不检查 pressed 状态（比如只写 <code>if (make_code == LSHIFT) shift_held_ = true;</code>，缺少 break code 的 <code>= false</code> 分支），Shift 键就会&quot;粘住&quot;——按下 Shift 后，即使松手了，后续所有按键仍然是大写。这个 bug 非常隐蔽，因为按 Shift 本身看起来很正常，只有松开之后才发现不对劲。</p><p><strong>验证</strong>: 在 host 端测试中，modifier 追踪相关的测试用例应该覆盖这些场景：LShift 按下设置 shift=true、LShift 释放设置 shift=false、RShift 按下也设置 shift=true、Ctrl 和 Alt 的完整生命周期。如果测试通过，说明 modifier 状态机的 press/release 逻辑是正确的。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>关键点</th></tr></thead><tbody><tr><td>扫描码集 1</td><td>Make: bit7=0, Break: bit7=1, make_code = sc &amp; 0x7F</td></tr><tr><td>查找表翻译</td><td>kScToLower[128] 和 kScToUpper[128]，索引 0 = 无映射</td></tr><tr><td>US QWERTY 布局</td><td>0x02-0x0B 数字行，0x10-0x1B QWERTY 行，0x1E-0x28 ASDF 行</td></tr><tr><td>Modifier 跟踪</td><td>三个布尔变量，每次 modifier 键 press/release 时更新</td></tr><tr><td>KeyEvent</td><td>ascii + scancode + pressed + shift/ctrl/alt 快照</td></tr><tr><td>数据驱动设计</td><td>查找表比 switch/case 更容易维护、审计和扩展</td></tr></tbody></table>',43)])])}const x=t(a,[["render",i]]);export{f as __pageData,x as default};
